import React, { useState, useEffect, useContext, useCallback } from 'react';
import {
  BrowserRouter as Router,
  Routes,
  Route,
  Navigate,
  Link,
  useNavigate,
  useLocation
} from 'react-router-dom';
import {
  ThemeProvider,
  createTheme,
  CssBaseline,
  AppBar,
  Toolbar,
  Typography,
  Button,
  Box,
  Card,
  CardContent,
  TextField,
  IconButton,
  Drawer,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  CircularProgress,
  Alert,
  Grid,
  LinearProgress,
  Chip,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Paper,
  Container,
  Avatar,
  Divider,
  CardActions,
  Stack,
  Fade,
  Grow,
  Zoom,
  ToggleButton,
  ToggleButtonGroup,
  FormControl,
  InputLabel,
  Select,
  MenuItem
} from '@mui/material';
import { alpha } from '@mui/material/styles';
import {
  Menu as MenuIcon,
  Dashboard as DashboardIcon,
  Upload as UploadIcon,
  Assessment as AssessmentIcon,
  Work as WorkIcon,
  History as HistoryIcon,
  Logout as LogoutIcon,
  Analytics as AnalyticsIcon,
  CheckCircle as CheckCircleIcon,
  TrendingUp as TrendingUpIcon,
  Description as DescriptionIcon,
  CloudUpload as CloudUploadIcon,
  Rocket as RocketIcon,
  Add as AddIcon,
  AutoAwesome as AutoAwesomeIcon,
  Psychology as PsychologyIcon,
  InsertDriveFile as InsertDriveFileIcon,
  PictureAsPdf as PictureAsPdfIcon,
  Article as ArticleIcon,
  Search as SearchIcon,
  Warning as WarningIcon,
  AppRegistration as AppRegistrationIcon,
  Delete as DeleteIcon,
  Refresh as RefreshIcon,
  Error as ErrorIcon,
  LocationOn as LocationIcon,
  AttachMoney as MoneyIcon,
  Email as EmailIcon,
  FileCopy as FileCopyIcon,
  Timeline as TimelineIcon,
  Lightbulb as LightbulbIcon
} from '@mui/icons-material';
import axios from 'axios';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:8000/api';

const api = axios.create({ baseURL: API_BASE_URL, headers: { 'Content-Type': 'application/json' } });

api.interceptors.request.use((config) => {
  const token = localStorage.getItem('access_token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('access_token');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

const theme = createTheme({
  palette: { primary: { main: '#ff69b4' }, background: { default: '#fff5f8' } },
  shape: { borderRadius: 16 },
  components: { MuiButton: { styleOverrides: { root: { textTransform: 'none', borderRadius: 12 } } } }
});

const AuthContext = React.createContext(null);

const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('access_token');
    if (token) {
      api.get('/auth/profile').then(res => setUser(res.data)).catch(() => {
        localStorage.removeItem('access_token');
        setUser(null);
      }).finally(() => setLoading(false));
    } else setLoading(false);
  }, []);

  const login = async (username, password) => {
    const formData = new FormData();
    formData.append('username', username);
    formData.append('password', password);
    const res = await axios.post(`${API_BASE_URL}/auth/login`, formData, { headers: { 'Content-Type': 'multipart/form-data' } });
    localStorage.setItem('access_token', res.data.access_token);
    const profile = await api.get('/auth/profile');
    setUser(profile.data);
    return profile.data;
  };

  const signup = async (userData) => {
    const res = await api.post('/auth/signup', userData);
    return res.data;
  };

  const logout = () => {
    localStorage.removeItem('access_token');
    setUser(null);
  };

  return <AuthContext.Provider value={{ user, login, signup, logout, loading }}>{children}</AuthContext.Provider>;
};

const useAuth = () => useContext(AuthContext);

const FileDropZone = ({ onFileChange, file }) => {
  const [dragging, setDragging] = useState(false);
  const handleDrop = useCallback((e) => { e.preventDefault(); setDragging(false); const dropped = e.dataTransfer.files[0]; if (dropped) onFileChange(dropped); }, [onFileChange]);
  return (
    <Box onDrop={handleDrop} onDragOver={(e) => { e.preventDefault(); setDragging(true); }} onDragLeave={() => setDragging(false)} onClick={() => document.getElementById('resume-file-input').click()} sx={{ border: `2px dashed ${dragging ? '#ff1493' : '#ff69b4'}`, borderRadius: 3, p: 5, textAlign: 'center', cursor: 'pointer', bgcolor: dragging ? alpha('#ff69b4', 0.08) : alpha('#ff69b4', 0.03) }}>
      <input id="resume-file-input" type="file" accept=".pdf,.docx" style={{ display: 'none' }} onChange={(e) => { if (e.target.files[0]) onFileChange(e.target.files[0]); }} />
      {file ? <Box><CheckCircleIcon sx={{ fontSize: 48, color: 'success.main', mb: 1 }} /><Typography variant="h6">{file.name}</Typography></Box> : <Box><CloudUploadIcon sx={{ fontSize: 56, color: '#ff69b4', mb: 1 }} /><Typography variant="h6">Drag & drop your resume here</Typography><Typography variant="body2" color="text.secondary">or click to browse</Typography></Box>}
    </Box>
  );
};

// Pages (simplified for brevity - include all your existing pages here)

const LoginPage = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      await login(username, password);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.detail || 'Invalid credentials');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #ff69b4 0%, #ff1493 100%)' }}>
      <Container maxWidth="sm">
        <Card sx={{ p: 4 }}>
          <Box textAlign="center" mb={4}><Avatar sx={{ bgcolor: '#ff69b4', width: 64, height: 64, margin: '0 auto', mb: 2 }}><AnalyticsIcon sx={{ fontSize: 32 }} /></Avatar><Typography variant="h4">Welcome Back</Typography></Box>
          <form onSubmit={handleSubmit}>
            <TextField fullWidth label="Username" value={username} onChange={(e) => setUsername(e.target.value)} margin="normal" required autoFocus />
            <TextField fullWidth label="Password" type="password" value={password} onChange={(e) => setPassword(e.target.value)} margin="normal" required />
            {error && <Alert severity="error" sx={{ mt: 2 }}>{error}</Alert>}
            <Button type="submit" fullWidth variant="contained" size="large" disabled={loading} sx={{ mt: 3 }}>{loading ? <CircularProgress size={24} /> : 'Sign In'}</Button>
          </form>
          <Box textAlign="center" mt={3}><Typography variant="body2">Don't have an account? <Link to="/signup" style={{ color: '#ff69b4' }}>Sign Up</Link></Typography></Box>
        </Card>
      </Container>
    </Box>
  );
};

const SignupPage = () => {
  const [formData, setFormData] = useState({ username: '', email: '', password: '' });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [loading, setLoading] = useState(false);
  const { signup } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      await signup(formData);
      setSuccess(true);
      setTimeout(() => navigate('/login'), 2000);
    } catch (err) {
      setError(err.response?.data?.detail || 'Signup failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box sx={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #ff69b4 0%, #ff1493 100%)' }}>
      <Container maxWidth="sm">
        <Card sx={{ p: 4 }}>
          <Box textAlign="center" mb={4}><Avatar sx={{ bgcolor: '#ff69b4', width: 64, height: 64, margin: '0 auto', mb: 2 }}><AppRegistrationIcon sx={{ fontSize: 32 }} /></Avatar><Typography variant="h4">Create Account</Typography></Box>
          <form onSubmit={handleSubmit}>
            <TextField fullWidth label="Username" value={formData.username} onChange={(e) => setFormData({ ...formData, username: e.target.value })} margin="normal" required autoFocus />
            <TextField fullWidth label="Email" type="email" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} margin="normal" required />
            <TextField fullWidth label="Password" type="password" value={formData.password} onChange={(e) => setFormData({ ...formData, password: e.target.value })} margin="normal" required inputProps={{ minLength: 6 }} />
            {error && <Alert severity="error" sx={{ mt: 2 }}>{error}</Alert>}
            {success && <Alert severity="success" sx={{ mt: 2 }}>Account created! Redirecting...</Alert>}
            <Button type="submit" fullWidth variant="contained" size="large" disabled={loading || success} sx={{ mt: 3 }}>{loading ? <CircularProgress size={24} /> : 'Create Account'}</Button>
          </form>
          <Box textAlign="center" mt={3}><Typography variant="body2">Already have an account? <Link to="/login" style={{ color: '#ff69b4' }}>Sign In</Link></Typography></Box>
        </Card>
      </Container>
    </Box>
  );
};

// Add all your other page components here (Dashboard, Upload, JobBoard, SalaryPredictor, CareerPath, CoverLetter, etc.)

const HomePage = () => {
  const navigate = useNavigate();
  return (
    <Box>
      <Box sx={{ background: 'linear-gradient(135deg, #ff69b4 0%, #ff1493 100%)', color: 'white', pt: 12, pb: 8 }}>
        <Container maxWidth="lg">
          <Grid container spacing={6} alignItems="center">
            <Grid item xs={12} md={6}>
              <Chip icon={<AutoAwesomeIcon />} label="AI-Powered Career Platform" sx={{ bgcolor: 'rgba(255,255,255,0.2)', color: 'white', mb: 3 }} />
              <Typography variant="h3" gutterBottom>Land Your Dream Job with AI</Typography>
              <Typography variant="h6" sx={{ mb: 4, opacity: 0.9 }}>ATS analysis, job matching, salary prediction, and more</Typography>
              <Stack direction="row" spacing={2}>
                <Button variant="contained" size="large" onClick={() => navigate('/signup')} sx={{ bgcolor: 'white', color: '#ff69b4' }} startIcon={<RocketIcon />}>Get Started Free</Button>
                <Button variant="outlined" size="large" onClick={() => navigate('/login')} sx={{ borderColor: 'white', color: 'white' }}>Sign In</Button>
              </Stack>
            </Grid>
          </Grid>
        </Container>
      </Box>
    </Box>
  );
};

// Add Layout component with sidebar menu
const Layout = ({ children }) => {
  const [mobileOpen, setMobileOpen] = useState(false);
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const menuItems = [
    { text: 'Dashboard', icon: <DashboardIcon />, path: '/dashboard' },
    { text: 'Upload Resume', icon: <UploadIcon />, path: '/upload' },
    { text: 'ATS Analysis', icon: <AssessmentIcon />, path: '/analyze' },
    { text: 'Job Board', icon: <SearchIcon />, path: '/jobs' },
    { text: 'Salary Predictor', icon: <MoneyIcon />, path: '/salary' },
    { text: 'Career Path', icon: <TimelineIcon />, path: '/career' },
    { text: 'Cover Letter', icon: <EmailIcon />, path: '/cover-letter' },
    { text: 'History', icon: <HistoryIcon />, path: '/history' },
  ];

  const drawerContent = (
    <Box>
      <Toolbar><AnalyticsIcon sx={{ color: '#ff69b4' }} /><Typography variant="h6" sx={{ color: '#ff69b4' }}>ResumeAI</Typography></Toolbar>
      <Divider />
      <List>
        {menuItems.map(item => (
          <ListItem button key={item.text} onClick={() => { navigate(item.path); setMobileOpen(false); }}>
            <ListItemIcon sx={{ color: '#ff69b4' }}>{item.icon}</ListItemIcon>
            <ListItemText primary={item.text} />
          </ListItem>
        ))}
      </List>
    </Box>
  );

  return (
    <Box sx={{ display: 'flex' }}>
      <AppBar position="fixed" sx={{ background: 'linear-gradient(135deg, #ff69b4 0%, #ff1493 100%)' }}>
        <Toolbar>
          <IconButton color="inherit" edge="start" onClick={() => setMobileOpen(true)} sx={{ mr: 2, display: { md: 'none' } }}><MenuIcon /></IconButton>
          <AnalyticsIcon sx={{ mr: 1 }} />
          <Typography variant="h6" sx={{ flexGrow: 1, cursor: 'pointer' }} onClick={() => navigate('/')}>ResumeAI</Typography>
          <Chip avatar={<Avatar sx={{ bgcolor: 'white', color: '#ff69b4' }}>{user?.username?.[0]?.toUpperCase()}</Avatar>} label={user?.username} sx={{ color: 'white', mr: 1 }} variant="outlined" />
          <IconButton color="inherit" onClick={logout}><LogoutIcon /></IconButton>
        </Toolbar>
      </AppBar>
      <Drawer variant="temporary" open={mobileOpen} onClose={() => setMobileOpen(false)} sx={{ display: { xs: 'block', md: 'none' } }}>{drawerContent}</Drawer>
      <Drawer variant="permanent" sx={{ display: { xs: 'none', md: 'block' }, width: 260, flexShrink: 0, '& .MuiDrawer-paper': { width: 260, mt: 8 } }} open>{drawerContent}</Drawer>
      <Box component="main" sx={{ flexGrow: 1, p: 3, mt: 8, backgroundColor: '#fff5f8', minHeight: '100vh' }}>{children}</Box>
    </Box>
  );
};

// Dashboard Page
const DashboardPage = () => {
  const [resumes, setResumes] = useState([]);
  const [loading, setLoading] = useState(true);
  useEffect(() => {
    api.get('/resume/list').then(res => { setResumes(res.data); setLoading(false); }).catch(() => setLoading(false));
  }, []);
  if (loading) return <CircularProgress />;
  return (
    <Box>
      <Typography variant="h4" gutterBottom>Welcome Back! 👋</Typography>
      <Grid container spacing={3}>
        {resumes.map(resume => (
          <Grid item xs={12} sm={6} md={4} key={resume.id}>
            <Card><CardContent><Typography variant="h6">{resume.name || resume.filename}</Typography><Typography variant="body2" color="text.secondary">Skills: {resume.skills?.join(', ') || 'None'}</Typography></CardContent></Card>
          </Grid>
        ))}
      </Grid>
    </Box>
  );
};

// Upload Page
const UploadPage = () => {
  const [file, setFile] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [result, setResult] = useState(null);
  const navigate = useNavigate();
  const handleUpload = async () => {
    if (!file) return;
    setUploading(true);
    const formData = new FormData();
    formData.append('file', file);
    try {
      const res = await api.post('/resume/upload', formData, { headers: { 'Content-Type': 'multipart/form-data' } });
      setResult(res.data);
      setTimeout(() => navigate('/analyze?resume=' + res.data.id), 2000);
    } catch (err) { alert('Upload failed'); } finally { setUploading(false); }
  };
  return (
    <Box><Typography variant="h4" gutterBottom>Upload Resume</Typography>
      <Card sx={{ p: 3 }}><FileDropZone file={file} onFileChange={setFile} />
        <Button variant="contained" fullWidth onClick={handleUpload} disabled={!file || uploading} sx={{ mt: 3 }}>{uploading ? 'Uploading...' : 'Upload Resume'}</Button>
        {result && <Alert severity="success" sx={{ mt: 2 }}>Uploaded! Redirecting...</Alert>}
      </Card>
    </Box>
  );
};

// Job Board Page
const JobBoardPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState('');
  const [keywords, setKeywords] = useState('');
  const [location, setLocation] = useState('');
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(false);
  useEffect(() => { api.get('/resume/list').then(res => setResumes(res.data)); }, []);
  const searchJobs = async () => {
    if (!selectedResume) return alert('Select a resume');
    setLoading(true);
    try {
      const res = await api.post('/jobs/search', { resume_id: parseInt(selectedResume), keywords, location, limit: 20 });
      setJobs(res.data.jobs);
    } catch (err) { alert('Search failed'); } finally { setLoading(false); }
  };
  return (
    <Box><Typography variant="h4" gutterBottom>Job Board</Typography>
      <Grid container spacing={4}>
        <Grid item xs={12} md={4}><Card sx={{ p: 3 }}>
          <FormControl fullWidth><InputLabel>Select Resume</InputLabel><Select value={selectedResume} onChange={(e) => setSelectedResume(e.target.value)}>{resumes.map(r => (<MenuItem key={r.id} value={r.id}>{r.name || r.filename}</MenuItem>))}</Select></FormControl>
          <TextField fullWidth label="Keywords" value={keywords} onChange={(e) => setKeywords(e.target.value)} sx={{ mt: 2 }} />
          <TextField fullWidth label="Location" value={location} onChange={(e) => setLocation(e.target.value)} sx={{ mt: 2 }} />
          <Button variant="contained" fullWidth onClick={searchJobs} disabled={loading} sx={{ mt: 2 }}>{loading ? 'Searching...' : 'Search Jobs'}</Button>
        </Card></Grid>
        <Grid item xs={12} md={8}>{jobs.map(job => (<Card key={job.id} sx={{ mb: 2 }}><CardContent><Typography variant="h6">{job.title}</Typography><Typography color="primary">{job.company} • {job.location}</Typography><Typography variant="body2" sx={{ mt: 1 }}>{job.description?.substring(0, 200)}...</Typography><Button size="small" href={job.apply_url} target="_blank">Apply Now</Button></CardContent></Card>))}</Grid>
      </Grid>
    </Box>
  );
};

// Salary Predictor Page
const SalaryPredictorPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState('');
  const [location, setLocation] = useState('');
  const [prediction, setPrediction] = useState(null);
  const [loading, setLoading] = useState(false);
  useEffect(() => { api.get('/resume/list').then(res => setResumes(res.data)); }, []);
  const predict = async () => {
    if (!selectedResume || !location) return alert('Select resume and location');
    setLoading(true);
    try {
      const res = await api.post('/salary/predict', { resume_id: parseInt(selectedResume), location });
      setPrediction(res.data);
    } catch (err) { alert('Prediction failed'); } finally { setLoading(false); }
  };
  return (
    <Box><Typography variant="h4" gutterBottom>Salary Predictor</Typography>
      <Grid container spacing={4}>
        <Grid item xs={12} md={4}><Card sx={{ p: 3 }}>
          <FormControl fullWidth><InputLabel>Select Resume</InputLabel><Select value={selectedResume} onChange={(e) => setSelectedResume(e.target.value)}>{resumes.map(r => (<MenuItem key={r.id} value={r.id}>{r.name || r.filename}</MenuItem>))}</Select></FormControl>
          <TextField fullWidth label="Location" value={location} onChange={(e) => setLocation(e.target.value)} sx={{ mt: 2 }} placeholder="e.g., Bangalore, San Francisco" />
          <Button variant="contained" fullWidth onClick={predict} disabled={loading} sx={{ mt: 2 }}>{loading ? 'Predicting...' : 'Predict Salary'}</Button>
        </Card></Grid>
        <Grid item xs={12} md={8}>{prediction && (<Card><CardContent><Typography variant="h5">Estimated Salary: {prediction.formatted_salary}</Typography><Typography variant="body2">{prediction.market_position}</Typography><Typography variant="subtitle2" sx={{ mt: 2 }}>Recommendations:</Typography>{prediction.recommendations?.map((rec, i) => (<Box key={i} display="flex" alignItems="center" gap={1}><LightbulbIcon sx={{ color: '#ff9800' }} /><Typography>{rec}</Typography></Box>))}</CardContent></Card>)}</Grid>
      </Grid>
    </Box>
  );
};

// Career Path Page
const CareerPathPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState('');
  const [paths, setPaths] = useState(null);
  const [loading, setLoading] = useState(false);
  useEffect(() => { api.get('/resume/list').then(res => setResumes(res.data)); }, []);
  const getPaths = async () => {
    if (!selectedResume) return alert('Select a resume');
    setLoading(true);
    try {
      const res = await api.post('/career/paths', { resume_id: parseInt(selectedResume) });
      setPaths(res.data);
    } catch (err) { alert('Failed'); } finally { setLoading(false); }
  };
  return (
    <Box><Typography variant="h4" gutterBottom>Career Path Advisor</Typography>
      <Grid container spacing={4}>
        <Grid item xs={12} md={4}><Card sx={{ p: 3 }}><FormControl fullWidth><InputLabel>Select Resume</InputLabel><Select value={selectedResume} onChange={(e) => setSelectedResume(e.target.value)}>{resumes.map(r => (<MenuItem key={r.id} value={r.id}>{r.name || r.filename}</MenuItem>))}</Select></FormControl><Button variant="contained" fullWidth onClick={getPaths} disabled={loading} sx={{ mt: 2 }}>{loading ? 'Analyzing...' : 'Get Recommendations'}</Button></Card></Grid>
        <Grid item xs={12} md={8}>{paths?.recommended_paths?.map((path, i) => (<Card key={i} sx={{ mb: 2 }}><CardContent><Typography variant="h5">{path.track}</Typography><Chip label={`${path.match_score}% Match`} sx={{ bgcolor: alpha('#4caf50', 0.1), color: '#4caf50' }} /><Typography sx={{ mt: 1 }}>Current: {path.current_level} → Next: {path.next_level}</Typography><Typography>Timeline: {path.estimated_timeline_months} months</Typography></CardContent></Card>))}</Grid>
      </Grid>
    </Box>
  );
};

// Cover Letter Page
const CoverLetterPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState('');
  const [jobDesc, setJobDesc] = useState('');
  const [company, setCompany] = useState('');
  const [letter, setLetter] = useState(null);
  const [loading, setLoading] = useState(false);
  useEffect(() => { api.get('/resume/list').then(res => setResumes(res.data)); }, []);
  const generate = async () => {
    if (!selectedResume || !jobDesc) return alert('Select resume and enter job description');
    setLoading(true);
    try {
      const res = await api.post('/cover-letter/generate', { resume_id: parseInt(selectedResume), job_description: jobDesc, company_name: company });
      setLetter(res.data);
    } catch (err) { alert('Generation failed'); } finally { setLoading(false); }
  };
  return (
    <Box><Typography variant="h4" gutterBottom>Cover Letter Generator</Typography>
      <Grid container spacing={4}>
        <Grid item xs={12} md={5}><Card sx={{ p: 3 }}>
          <FormControl fullWidth><InputLabel>Select Resume</InputLabel><Select value={selectedResume} onChange={(e) => setSelectedResume(e.target.value)}>{resumes.map(r => (<MenuItem key={r.id} value={r.id}>{r.name || r.filename}</MenuItem>))}</Select></FormControl>
          <TextField fullWidth multiline rows={4} label="Job Description" value={jobDesc} onChange={(e) => setJobDesc(e.target.value)} sx={{ mt: 2 }} />
          <TextField fullWidth label="Company Name (optional)" value={company} onChange={(e) => setCompany(e.target.value)} sx={{ mt: 2 }} />
          <Button variant="contained" fullWidth onClick={generate} disabled={loading} sx={{ mt: 2 }}>{loading ? 'Generating...' : 'Generate Cover Letter'}</Button>
        </Card></Grid>
        <Grid item xs={12} md={7}>{letter && (<Card><CardContent><Typography variant="h6">Your Cover Letter</Typography><Paper sx={{ p: 2, bgcolor: '#f5f5f5', mt: 1, whiteSpace: 'pre-wrap' }}><Typography>{letter.cover_letter}</Typography></Paper></CardContent></Card>)}</Grid>
      </Grid>
    </Box>
  );
};

// ATS Analysis Page
const ATSAnalysisPage = () => {
  const [resumes, setResumes] = useState([]);
  const [selectedResume, setSelectedResume] = useState('');
  const [analysis, setAnalysis] = useState(null);
  const [loading, setLoading] = useState(false);
  const location = useLocation();
  useEffect(() => {
    api.get('/resume/list').then(res => setResumes(res.data));
    const params = new URLSearchParams(location.search);
    const id = params.get('resume');
    if (id) setSelectedResume(id);
  }, [location]);
  const analyze = async () => {
    if (!selectedResume) return;
    setLoading(true);
    try {
      const res = await api.post('/analyze/advanced-ats', { resume_id: parseInt(selectedResume) });
      setAnalysis(res.data);
    } catch (err) { alert('Analysis failed'); } finally { setLoading(false); }
  };
  return (
    <Box><Typography variant="h4" gutterBottom>ATS Analysis</Typography>
      <Grid container spacing={4}>
        <Grid item xs={12} md={4}><Card sx={{ p: 3 }}><FormControl fullWidth><InputLabel>Select Resume</InputLabel><Select value={selectedResume} onChange={(e) => setSelectedResume(e.target.value)}>{resumes.map(r => (<MenuItem key={r.id} value={r.id}>{r.name || r.filename}</MenuItem>))}</Select></FormControl><Button variant="contained" fullWidth onClick={analyze} disabled={loading} sx={{ mt: 2 }}>{loading ? 'Analyzing...' : 'Analyze'}</Button></Card></Grid>
        <Grid item xs={12} md={8}>{analysis && (<Card><CardContent><Typography variant="h3" align="center">{Math.round(analysis.ats_score)}</Typography><LinearProgress variant="determinate" value={analysis.ats_score} sx={{ mb: 2 }} /><Typography variant="h6">Strengths</Typography>{analysis.strengths?.map((s, i) => (<Box key={i} display="flex" alignItems="center" gap={1}><CheckCircleIcon sx={{ color: '#4caf50' }} /><Typography>{s}</Typography></Box>))}<Typography variant="h6" sx={{ mt: 2 }}>Areas to Improve</Typography>{analysis.weaknesses?.map((w, i) => (<Box key={i} display="flex" alignItems="center" gap={1}><WarningIcon sx={{ color: '#ff9800' }} /><Typography>{w}</Typography></Box>))}</CardContent></Card>)}</Grid>
      </Grid>
    </Box>
  );
};

// History Page
const HistoryPage = () => {
  const [history, setHistory] = useState([]);
  useEffect(() => { api.get('/analysis/history').then(res => setHistory(res.data)); }, []);
  return (
    <Box><Typography variant="h4" gutterBottom>Analysis History</Typography>
      {history.map(h => (<Card key={h.id} sx={{ mb: 2 }}><CardContent><Typography variant="h6">{h.resume_name}</Typography><Typography variant="body2">Type: {h.analysis_type} | Score: {h.ats_score || h.match_percentage}%</Typography><Typography variant="caption">{new Date(h.created_at).toLocaleDateString()}</Typography></CardContent></Card>))}
    </Box>
  );
};

// App Routes
const AppRoutes = () => {
  const { user, loading } = useAuth();
  if (loading) return <CircularProgress sx={{ position: 'absolute', top: '50%', left: '50%' }} />;
  return (
    <Routes>
      <Route path="/" element={<HomePage />} />
      <Route path="/login" element={user ? <Navigate to="/dashboard" /> : <LoginPage />} />
      <Route path="/signup" element={user ? <Navigate to="/dashboard" /> : <SignupPage />} />
      <Route path="/dashboard" element={user ? <Layout><DashboardPage /></Layout> : <Navigate to="/login" />} />
      <Route path="/upload" element={user ? <Layout><UploadPage /></Layout> : <Navigate to="/login" />} />
      <Route path="/analyze" element={user ? <Layout><ATSAnalysisPage /></Layout> : <Navigate to="/login" />} />
      <Route path="/jobs" element={user ? <Layout><JobBoardPage /></Layout> : <Navigate to="/login" />} />
      <Route path="/salary" element={user ? <Layout><SalaryPredictorPage /></Layout> : <Navigate to="/login" />} />
      <Route path="/career" element={user ? <Layout><CareerPathPage /></Layout> : <Navigate to="/login" />} />
      <Route path="/cover-letter" element={user ? <Layout><CoverLetterPage /></Layout> : <Navigate to="/login" />} />
      <Route path="/history" element={user ? <Layout><HistoryPage /></Layout> : <Navigate to="/login" />} />
    </Routes>
  );
};

const App = () => (
  <ThemeProvider theme={theme}>
    <CssBaseline />
    <AuthProvider>
      <Router>
        <AppRoutes />
      </Router>
    </AuthProvider>
  </ThemeProvider>
);

export default App;
